// Configuration
const locationId = 'x7nLyDSHiewYRtwYlX0h';
const tags = ['platinum', 'software subscription'];
const ghlApiKey = $env.GHL_LOCATION_API_KEY;

let allContacts = [];

for (const tag of tags) {
  let skip = 0;
  const limit = 100;
  let hasMore = true;

  while (hasMore) {
    const url = `https://services.leadconnectorhq.com/contacts/?locationId=${locationId}&limit=${limit}${skip ? '&skip=' + skip : ''}&query=&tag=${encodeURIComponent(tag)}`;

    const response = await fetch(url, {
      headers: {
        'Authorization': `Bearer ${ghlApiKey}`,
        'Version': '2021-07-28',
        'Accept': 'application/json'
      }
    });

    const data = await response.json();
    const contacts = data.contacts || [];

    for (const c of contacts) {
      if (!allContacts.find(existing => existing.id === c.id)) {
        allContacts.push({
          id: c.id,
          firstName: c.firstName || '',
          lastName: c.lastName || '',
          email: c.email || '',
          phone: c.phone || '',
          tags: c.tags || []
        });
      }
    }

    skip += limit;
    hasMore = contacts.length === limit;
  }
}

return allContacts.map(c => ({ json: c }));

const contact = $input.first().json;
const locationId = 'x7nLyDSHiewYRtwYlX0h';
const ghlApiKey = $env.GHL_LOCATION_API_KEY;

// Get conversations for this contact
const convUrl = `https://services.leadconnectorhq.com/conversations/search?locationId=${locationId}&contactId=${contact.id}&limit=5`;
const convResponse = await fetch(convUrl, {
  method: 'GET',
  headers: {
    'Authorization': `Bearer ${ghlApiKey}`,
    'Version': '2021-07-28',
    'Accept': 'application/json'
  }
});
const convData = await convResponse.json();
const conversations = convData.conversations || [];

let allMessages = [];

for (const conv of conversations) {
  // Get messages for each conversation
  const msgUrl = `https://services.leadconnectorhq.com/conversations/${conv.id}/messages?limit=100`;
  const msgResponse = await fetch(msgUrl, {
    headers: {
      'Authorization': `Bearer ${ghlApiKey}`,
      'Version': '2021-07-28',
      'Accept': 'application/json'
    }
  });
  const msgData = await msgResponse.json();
  const messages = msgData.messages || [];

  // Filter to SMS and email only, skip system messages
  const filtered = messages
    .filter(m => ['TYPE_SMS', 'TYPE_EMAIL'].includes(m.type) && m.body)
    .map(m => ({
      type: m.type === 'TYPE_SMS' ? 'SMS' : 'Email',
      direction: m.direction || 'outbound',
      body: m.body.substring(0, 2000),
      date: m.dateAdded
    }));

  allMessages = allMessages.concat(filtered);
}

// Sort by date
allMessages.sort((a, b) => new Date(a.date) - new Date(b.date));

return [{
  json: {
    contactId: contact.id,
    contactName: `${contact.firstName} ${contact.lastName}`.trim(),
    contactEmail: contact.email,
    contactTags: contact.tags,
    messageCount: allMessages.length,
    messages: allMessages
  }
}];

const item = $input.first().json;
const messages = item.messages || [];

// Build a conversation transcript
let transcript = `Contact: ${item.contactName} (${item.contactEmail})\nTags: ${item.contactTags.join(', ')}\n\n--- CONVERSATION ---\n\n`;

for (const msg of messages) {
  const speaker = msg.direction === 'inbound' ? `[CUSTOMER - ${item.contactName}]` : '[GM BAPTIST TEAM]';
  // Truncate long emails
  const body = msg.body.length > 500 ? msg.body.substring(0, 500) + '...' : msg.body;
  transcript += `${speaker} (${msg.type}, ${msg.date}):\n${body}\n\n`;
}

// Truncate overall transcript to ~8000 chars to fit in Claude context
if (transcript.length > 8000) {
  transcript = transcript.substring(0, 8000) + '\n\n[TRUNCATED]';
}

return [{
  json: {
    contactId: item.contactId,
    contactName: item.contactName,
    contactTags: item.contactTags,
    messageCount: item.messageCount,
    transcript: transcript
  }
}];

