const item = $input.first().json;
const prevItem = $('Format Transcript').first().json;

// Parse Claude's response
let qaData = { questions: [] };
try {
  const content = item.content[0].text;
  // Find JSON in the response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    qaData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  // If parsing fails, skip this contact
}

return [{
  json: {
    contactName: prevItem.contactName,
    contactTags: prevItem.contactTags,
    questions: qaData.questions || []
  }
}];

// Collect all Q&A pairs from all contacts
const allItems = $('Parse Q&A Response').all();
let allQuestions = [];

for (const item of allItems) {
  const questions = item.json.questions || [];
  for (const q of questions) {
    allQuestions.push({
      question: q.question,
      answer: q.answer,
      topic: q.topic,
      contactName: item.json.contactName,
      contactTags: item.json.contactTags
    });
  }
}

return [{
  json: {
    totalQuestions: allQuestions.length,
    questions: allQuestions
  }
}];

