const item = $input.first().json;
const aggregate = $('Aggregate All Q&As').first().json;

let faqData = {};
try {
  const content = item.content[0].text;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    faqData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  faqData = { error: 'Failed to parse FAQ response', raw: item.content?.[0]?.text || 'No content' };
}

return [{
  json: {
    generatedAt: new Date().toISOString(),
    totalContactsAnalyzed: $('Fetch Tagged Contacts').all().length,
    totalQuestionsExtracted: aggregate.totalQuestions,
    ...faqData
  }
}];
